from flask import Flask, render_template, redirect, url_for, request, session, flash
from datetime import datetime, timedelta
import os

app = Flask(__name__)
app.secret_key = 'secret-key-for-session'
DATA_DIR = 'data'

# Utility functions for reading and writing pipe-delimited files
def read_pipe_file(filename):
    filepath = os.path.join(DATA_DIR, filename)
    if not os.path.exists(filepath):
        return []
    with open(filepath, 'r', encoding='utf-8') as f:
        lines = [line.strip() for line in f if line.strip()]
        return [line.split('|') for line in lines]

def write_pipe_file(filename, rows):
    filepath = os.path.join(DATA_DIR, filename)
    with open(filepath, 'w', encoding='utf-8') as f:
        for row in rows:
            f.write('|'.join(str(x) for x in row) + '\n')

# Get current logged-in username - emulated
def current_username():
    return session.get('username', 'john_reader')

# USERS

def get_user(username):
    rows = read_pipe_file('users.txt')
    for r in rows:
        if r[0] == username:
            return {
                'username': r[0],
                'email': r[1],
                'phone': r[2],
                'address': r[3]
            }
    return None

# BOOKS

def get_all_books():
    books = []
    rows = read_pipe_file('books.txt')
    for r in rows:
        try:
            books.append({
                'book_id': int(r[0]),
                'title': r[1],
                'author': r[2],
                'isbn': r[3],
                'genre': r[4],
                'publisher': r[5],
                'year': int(r[6]),
                'description': r[7],
                'status': r[8],
                'avg_rating': float(r[9])
            })
        except Exception:
            continue
    return books

def get_book(book_id):
    for book in get_all_books():
        if book['book_id'] == book_id:
            return book
    return None

def update_book_status(book_id, status):
    rows = read_pipe_file('books.txt')
    changed = False
    for i, r in enumerate(rows):
        if int(r[0]) == book_id:
            r[8] = status
            rows[i] = r
            changed = True
            break
    if changed:
        write_pipe_file('books.txt', rows)
    return changed

# BORROWINGS

def get_all_borrowings():
    borrows = []
    rows = read_pipe_file('borrowings.txt')
    for r in rows:
        try:
            borrows.append({
                'borrow_id': int(r[0]),
                'username': r[1],
                'book_id': int(r[2]),
                'borrow_date': r[3],
                'due_date': r[4],
                'return_date': r[5],
                'status': r[6],
                'fine_amount': float(r[7])
            })
        except Exception:
            continue
    return borrows

def get_borrowing(borrow_id):
    for b in get_all_borrowings():
        if b['borrow_id'] == borrow_id:
            return b
    return None

def user_borrowings(username):
    return [b for b in get_all_borrowings() if b['username'] == username]

def add_borrowing(username, book_id):
    borrows = get_all_borrowings()
    next_id = max([b['borrow_id'] for b in borrows], default=0) + 1
    today = datetime.today().date()
    due = today + timedelta(days=14)
    new_borrow = {
        'borrow_id': next_id,
        'username': username,
        'book_id': book_id,
        'borrow_date': today.strftime('%Y-%m-%d'),
        'due_date': due.strftime('%Y-%m-%d'),
        'return_date': '',
        'status': 'Active',
        'fine_amount': 0.0
    }
    borrows.append(new_borrow)
    rows = []
    for b in borrows:
        rows.append([
            b['borrow_id'], b['username'], b['book_id'], b['borrow_date'], b['due_date'], b['return_date'], b['status'], f"{b['fine_amount']:.2f}"
        ])
    write_pipe_file('borrowings.txt', rows)
    return new_borrow

def update_borrowing(borrow_id, updates):
    borrows = get_all_borrowings()
    updated = False
    for b in borrows:
        if b['borrow_id'] == borrow_id:
            for k, v in updates.items():
                if k in b:
                    b[k] = v
            updated = True
            break
    if updated:
        rows = []
        for b in borrows:
            rows.append([
                b['borrow_id'], b['username'], b['book_id'], b['borrow_date'], b['due_date'], b['return_date'], b['status'], f"{b['fine_amount']:.2f}"
            ])
        write_pipe_file('borrowings.txt', rows)
    return updated

# RESERVATIONS

def get_all_reservations():
    res_list = []
    rows = read_pipe_file('reservations.txt')
    for r in rows:
        try:
            res_list.append({
                'reservation_id': int(r[0]),
                'username': r[1],
                'book_id': int(r[2]),
                'reservation_date': r[3],
                'status': r[4]
            })
        except Exception:
            continue
    return res_list

def user_reservations(username):
    return [r for r in get_all_reservations() if r['username'] == username]

def update_reservation_status(reservation_id, status):
    rows = read_pipe_file('reservations.txt')
    updated = False
    for i, r in enumerate(rows):
        if int(r[0]) == reservation_id:
            r[4] = status
            rows[i] = r
            updated = True
            break
    if updated:
        write_pipe_file('reservations.txt', rows)
    return updated

# REVIEWS

def get_all_reviews():
    reviews = []
    rows = read_pipe_file('reviews.txt')
    for r in rows:
        try:
            reviews.append({
                'review_id': int(r[0]),
                'username': r[1],
                'book_id': int(r[2]),
                'rating': int(r[3]),
                'review_text': r[4],
                'review_date': r[5]
            })
        except Exception:
            continue
    return reviews

def user_reviews(username):
    return [r for r in get_all_reviews() if r['username'] == username]

def book_reviews(book_id):
    return [r for r in get_all_reviews() if r['book_id'] == book_id]

def get_review(review_id):
    for r in get_all_reviews():
        if r['review_id'] == review_id:
            return r
    return None

def get_user_book_review(username, book_id):
    for r in get_all_reviews():
        if r['username'] == username and r['book_id'] == book_id:
            return r
    return None

def add_or_update_review(username, book_id, rating, review_text):
    reviews = get_all_reviews()
    existing = get_user_book_review(username, book_id)
    today_str = datetime.today().strftime('%Y-%m-%d')
    if existing:
        for r in reviews:
            if r['review_id'] == existing['review_id']:
                r['rating'] = rating
                r['review_text'] = review_text
                r['review_date'] = today_str
                break
    else:
        new_id = max([r['review_id'] for r in reviews], default=0) + 1
        reviews.append({
            'review_id': new_id,
            'username': username,
            'book_id': book_id,
            'rating': rating,
            'review_text': review_text,
            'review_date': today_str
        })
    rows = []
    for r in reviews:
        rows.append([r['review_id'], r['username'], r['book_id'], r['rating'], r['review_text'], r['review_date']])
    write_pipe_file('reviews.txt', rows)

# BORROW HISTORY

def get_borrow_history(username):
    borrows = get_all_borrowings()
    history = []
    for b in borrows:
        if b['username'] == username and b['status'] in ('Returned', 'Overdue'):
            book = get_book(b['book_id'])
            if not book:
                continue
            history.append({
                'book_title': book['title'],
                'borrow_date': b['borrow_date'],
                'return_date': b['return_date']
            })
    return history

# ROUTES

@app.route('/')
def root_redirect():
    return redirect(url_for('dashboard_page'))

@app.route('/dashboard')
def dashboard_page():
    username = current_username()
    return render_template('dashboard.html', username=username)

@app.route('/catalog')
def book_catalog_page():
    books = get_all_books()
    return render_template('catalog.html', books=books)

@app.route('/book/<int:book_id>')
def book_details_page(book_id):
    book = get_book(book_id)
    if not book:
        flash('Book not found.')
        return redirect(url_for('book_catalog_page'))
    reviews = book_reviews(book_id)
    return render_template('book_details.html', book=book, reviews=reviews)

@app.route('/borrow/<int:book_id>', methods=['GET','POST'])
def borrow_confirmation_page(book_id):
    username = current_username()
    book = get_book(book_id)
    if not book:
        flash('Book not found.')
        return redirect(url_for('book_catalog_page'))
    if request.method == 'GET':
        due_date = (datetime.today() + timedelta(days=14)).strftime('%Y-%m-%d')
        simple_book = {'book_id': book['book_id'], 'title': book['title'], 'author': book['author']}
        return render_template('borrow_confirmation.html', book=simple_book, due_date=due_date)
    else:
        if book['status'] != 'Available':
            flash('Book not available for borrowing.')
            return redirect(url_for('book_details_page', book_id=book_id))
        add_borrowing(username, book_id)
        update_book_status(book_id, 'Borrowed')
        flash('Borrowing confirmed.')
        return redirect(url_for('confirm_borrow', book_id=book_id))

@app.route('/confirm_borrow/<int:book_id>', methods=['POST'])
def confirm_borrow(book_id):
    flash('Borrow processed successfully.')
    return redirect(url_for('dashboard_page'))

@app.route('/my_borrows')
def my_borrows_page():
    username = current_username()
    borrows = user_borrows(username)
    today = datetime.today().date()
    for b in borrows:
        if b['status'] == 'Active':
            due = datetime.strptime(b['due_date'], '%Y-%m-%d').date()
            if today > due:
                overdue_days = (today - due).days
                fine = overdue_days * 0.5
                b['fine_amount'] = fine
                b['status'] = 'Overdue'
                update_borrowing(b['borrow_id'], {'status': 'Overdue', 'fine_amount': fine})
    for b in borrows:
        book = get_book(b['book_id'])
        b['book_title'] = book['title'] if book else 'Unknown'
    return render_template('my_borrows.html', borrows=borrows)

@app.route('/return_borrow/<int:borrow_id>', methods=['POST'])
def return_borrow(borrow_id):
    username = current_username()
    borrow = get_borrow(borrow_id)
    if not borrow or borrow['username'] != username or borrow['status'] == 'Returned':
        flash('Invalid return request.')
        return redirect(url_for('my_borrows_page'))
    return_date = datetime.today().strftime('%Y-%m-%d')
    update_borrowing(borrow_id, {'return_date': return_date, 'status': 'Returned', 'fine_amount': 0.0})
    update_book_status(borrow['book_id'], 'Available')
    book = get_book(borrow['book_id'])
    confirmation_message = f"Book '{book['title']}' returned successfully."
    return render_template('return_confirmation.html', borrow_id=borrow_id, book_title=book['title'], return_date=return_date, confirmation_message=confirmation_message)

@app.route('/my_reservations')
def my_reservations_page():
    username = current_username()
    reservations = user_reservations(username)
    for r in reservations:
        book = get_book(r['book_id'])
        r['book_title'] = book['title'] if book else 'Unknown'
    return render_template('my_reservations.html', reservations=reservations)

@app.route('/cancel_reservation/<int:reservation_id>', methods=['POST'])
def cancel_reservation(reservation_id):
    username = current_username()
    reservations = user_reservations(username)
    for r in reservations:
        if r['reservation_id'] == reservation_id:
            if r['status'] == 'Cancelled':
                flash('Reservation already cancelled.')
                return redirect(url_for('my_reservations_page'))
            update_reservation_status(reservation_id, 'Cancelled')
            flash('Reservation cancelled successfully.')
            return redirect(url_for('my_reservations_page'))
    flash('Reservation not found or unauthorized.')
    return redirect(url_for('my_reservations_page'))

@app.route('/my_reviews')
def my_reviews_page():
    username = current_username()
    reviews = user_reviews(username)
    for r in reviews:
        book = get_book(r['book_id'])
        r['book_title'] = book['title'] if book else 'Unknown'
    return render_template('my_reviews.html', reviews=reviews)

@app.route('/write_review/<int:book_id>', methods=['GET', 'POST'])
def write_review_page(book_id):
    username = current_username()
    book = get_book(book_id)
    if not book:
        flash('Book not found.')
        return redirect(url_for('book_catalog_page'))
    existing_review = get_user_book_review(username, book_id)
    book_info = {'book_id': book['book_id'], 'title': book['title']}
    if request.method == 'GET':
        return render_template('write_review.html', book=book_info, existing_review=existing_review)
    rating_str = request.form.get('rating', '')
    try:
        rating = int(rating_str)
        if rating < 1 or rating > 5:
            raise ValueError
    except:
        flash('Invalid rating.')
        return render_template('write_review.html', book=book_info, existing_review=existing_review)
    review_text = request.form.get('review_text', '').strip()
    if not review_text:
        flash('Review text cannot be empty.')
        return render_template('write_review.html', book=book_info, existing_review=existing_review)
    add_or_update_review(username, book_id, rating, review_text)
    flash('Review submitted successfully.')
    return redirect(url_for('book_details_page', book_id=book_id))

@app.route('/submit_review/<int:book_id>', methods=['POST'])
def submit_review(book_id):
    confirmation_message = 'Review submitted successfully.'
    flash(confirmation_message)
    return redirect(url_for('book_details_page', book_id=book_id))

@app.route('/profile', methods=['GET','POST'])
def profile_page():
    username = current_username()
    user = get_user(username)
    if not user:
        flash('User not found.')
        return redirect(url_for('dashboard_page'))
    borrow_history = get_borrow_history(username)
    if request.method == 'GET':
        return render_template('profile.html', username=username, email=user['email'], borrow_history=borrow_history)
    new_email = request.form.get('email')
    users = read_pipe_file('users.txt')
    for i, u in enumerate(users):
        if u[0] == username:
            users[i][1] = new_email
            break
    write_pipe_file('users.txt', users)
    flash('Profile updated.')
    return redirect(url_for('profile_page'))

@app.route('/payment/<int:fine_id>', methods=['GET','POST'])
def payment_confirmation_page(fine_id):
    username = current_username()
    fines = read_pipe_file('fines.txt')
    fine = None
    for f in fines:
        if int(f[0]) == fine_id and f[1] == username:
            fine = {'fine_id': int(f[0]), 'amount': float(f[3])}
            break
    if not fine:
        flash('Fine not found or unauthorized.')
        return redirect(url_for('profile_page'))
    if request.method == 'GET':
        return render_template('payment_confirmation.html', fine=fine)
    return redirect(url_for('confirm_payment', fine_id=fine_id))

@app.route('/confirm_payment/<int:fine_id>', methods=['POST'])
def confirm_payment(fine_id):
    username = current_username()
    fines = read_pipe_file('fines.txt')
    updated = False
    for i, f in enumerate(fines):
        if int(f[0]) == fine_id and f[1] == username:
            f[4] = 'Paid'
            fines[i] = f
            updated = True
            break
    if updated:
        write_pipe_file('fines.txt', fines)
        confirmation_message = 'Payment processed successfully.'
        flash(confirmation_message)
    else:
        confirmation_message = 'Payment confirmation failed.'
        flash(confirmation_message)
    return render_template('payment_confirmation.html', confirmation_message=confirmation_message, fine=None)

if __name__ == '__main__':
    if not os.path.exists(DATA_DIR):
        os.mkdir(DATA_DIR)
    app.run(debug=True)


